import { Link } from 'gatsby';
import React from 'react';
import { PaperType } from 'types/data';
import { AuthorName, PaperName, PaperWrapper, Published } from './styles';

interface IProps {
  paper: PaperType;
}

const ShortenName = (name: string): string => name.split(',')[0] + ' et al.';

const PaperList = ({ paper }: IProps) => {
  return (
    <PaperWrapper>
      <PaperName>
        <Link to={paper.slug} style={{ textDecoration: 'none', color: 'black' }}>
          {paper.paperName}
        </Link>
      </PaperName>
      <AuthorName>[{ShortenName(paper.author)}]</AuthorName>
      <Published>Published : {paper.publish.split('T')[0]}</Published>
    </PaperWrapper>
  );
};

export default PaperList;
